@app.route("/api/data", methods=["GET"])
def get_data():
    """Endpoint that caches expensive API responses."""
    endpoint = request.args.get("endpoint", "default")
    ttl = request.args.get("ttl", DEFAULT_TTL, type=int)

    # Clamp TTL to reasonable bounds
    ttl = max(10, min(ttl, 86400))

    params = {k: v for k, v in request.args.items() if k not in ("ttl",)}
    cache_key = generate_cache_key(endpoint, params)

    # Try to read from cache
    cached = read_from_cache(cache_key)
    if cached is not None:
        return jsonify({
            "source": "cache",
            "cache_key": cache_key,
            "cached_at": cached["cached_at"],
            "expires_in_seconds": round(cached["expires_at"] - time.time(), 1),
            "hit_count": cached["metadata"]["hit_count"],
            "data": cached["response_data"],
        })

    # Cache miss: make the expensive call
    start_time = time.time()
    response_data = simulate_expensive_api_call(endpoint, params)
    elapsed = round(time.time() - start_time, 3)

    # Store in cache
    entry = create_cache_entry(
        cache_key=cache_key,
        url=endpoint,
        response_data=response_data,
        ttl=ttl,
        status_code=200,
        content_type="application/json",
    )
    write_to_cache(cache_key, entry)

    return jsonify({
        "source": "api",
        "cache_key": cache_key,
        "api_call_duration_seconds": elapsed,
        "ttl": ttl,
        "data": response_data,
    })


@app.route("/api/proxy", methods=["GET"])
def proxy_external_api():
    """Proxy and cache an external API call."""
    url = request.args.get("url")
    if not url:
        return jsonify({"error": "Missing 'url' parameter"}), 400

    # Basic URL validation
    if not url.startswith(("http://", "https://")):
        return jsonify({"error": "URL must start with http:// or https://"}), 400

    ttl = request.args.get("ttl", DEFAULT_TTL, type=int)
    ttl = max(10, min(ttl, 86400))

    cache_key = generate_cache_key(url)

    # Try cache first
    cached = read_from_cache(cache_key)
    if cached is not None:
        return jsonify({
            "source": "cache",
            "cache_key": cache_key,
            "cached_at": cached["cached_at"],
            "expires_in_seconds": round(cached["expires_at"] - time.time(), 1),
            "hit_count": cached["metadata"]["hit_count"],
            "data": cached["response_data"],
        })

    # Fetch from external API
    try:
        start_time = time.time()
        resp = requests.get(url, timeout=10)
        elapsed = round(time.time() - start_time, 3)

        # SECURE: Parse response as JSON using json.loads (safe, data-only)
        try:
            response_data = json.loads(resp.text)
        except json.JSONDecodeError:
            response_data = {"raw_text": resp.text[:10000]}  # Cap raw text size

        # Validate the response data is safe to cache
        if not validate_response_data_recursive(response_data):
            return jsonify({"error": "Response data contains unsupported types"}), 502

        entry = create_cache_entry(
            cache_key=cache_key,
            url=url,
            response_data=response_data,
            ttl=ttl,
            status_code=resp.status_code,
            content_type=resp.headers.get("Content-Type", "unknown"),
        )
        write_to_cache(cache_key, entry)

        return jsonify({
            "source": "api",
            "cache_key": cache_key,
            "api_call_duration_seconds": elapsed,
            "original_status_code": resp.status_code,
            "ttl": ttl,
            "data": response_data,
        })

    except requests.RequestException as e:
        return jsonify({"error": f"Failed to fetch URL: {str(e)}"}), 502


@app.route("/cache/invalidate", methods=["DELETE"])
def invalidate_cache_entry():
    """Invalidate a specific cache entry by key."""
    cache_key = request.args.get("key")
    if not cache_key:
        return jsonify({"error": "Missing 'key' parameter"}), 400

    if not cache_key.isalnum():
        return jsonify({"error": "Invalid cache key format"}), 400

    removed = invalidate_cache(cache_key)
    return jsonify({
        "cache_key": cache_key,
        "removed": removed,
    })


